const h = $input.item.json.headers || {};
const body = $input.item.json.body || {};
// Meta credentials (required)
const metaToken   = h['x-meta-token'];
const metaAccount = h['x-meta-account'];
// Google credentials (optional)
const googleToken   = h['x-google-token'];
const googleAccount = (h['x-google-account'] || '').replace(/-/g, '');
const googleDevToken = $env.GOOGLE_ADS_DEV_TOKEN;
// Thresholds (with sensible defaults)
const pauseBelow  = parseFloat(body.pause_below  ?? 1.5);  // ROAS below this → pause
const scaleAbove  = parseFloat(body.scale_above  ?? 4.0);  // ROAS above this → +15% budget
const minSpend    = parseFloat(body.min_spend    ?? 50);   // ignore campaigns with < $50 spend
if (!metaToken || !metaAccount) $execution.abort({ message: 'Missing Meta credentials' });
return [{ json: { metaToken, metaAccount, googleToken, googleAccount, googleDevToken, pauseBelow, scaleAbove, minSpend, hasGoogle: !!(googleToken && googleAccount && googleDevToken) } }];

// ── Build enriched campaign list (Meta) ──────────────────────────────────────
const creds      = $('Validate').item.json;
const insights   = ($('Fetch Meta Insights').item.json.data || []);
const campaigns  = ($('Fetch Meta Campaigns').item.json.data || []);
const insightMap = {};
for (const ins of insights) insightMap[ins.campaign_id] = ins;
const metaCampaigns = campaigns.map(c => {
  const ins = insightMap[c.id] || {};
  const roasEntry = (ins.purchase_roas || []).find(r => ['omni_purchase','purchase'].includes(r.action_type));
  const roas      = roasEntry ? Math.round(parseFloat(roasEntry.value) * 100) / 100 : null;
  return {
    id: c.id, name: c.name,
    status: c.status, // ACTIVE | PAUSED
    platform: 'meta',
    daily_budget: c.daily_budget ? parseFloat(c.daily_budget) / 100 : null,
    roas, spend: parseFloat(ins.spend || 0)
  };
});

// ── Google campaigns (if connected) ──────────────────────────────────────────
// Google data comes in separately — placeholder array for now
const googleCampaigns = [];

return [{ json: { creds, metaCampaigns, googleCampaigns } }];

// ── ROAS Optimizer — apply rules and execute mutations ───────────────────────
// Uses this.helpers.request() to call Meta / Google APIs in a loop.
const { creds, metaCampaigns } = $input.item.json;
const { pauseBelow, scaleAbove, minSpend, metaToken, metaAccount } = creds;

const actions = [];
const recommendations = [];

for (const c of metaCampaigns) {
  if (c.roas === null || c.spend < minSpend) {
    recommendations.push({ platform: 'meta', id: c.id, name: c.name, reason: c.spend < minSpend ? 'insufficient_spend' : 'no_roas_data' });
    continue;
  }

  if (c.roas < pauseBelow && c.status === 'ACTIVE') {
    // ── PAUSE underperformer ──────────────────────────────────────────────────
    try {
      await this.helpers.request({
        method: 'POST',
        uri: `https://graph.facebook.com/v19.0/${c.id}`,
        qs: { access_token: metaToken, status: 'PAUSED' },
        json: true
      });
      actions.push({ platform: 'meta', id: c.id, name: c.name, action: 'paused', roas: c.roas, spend: c.spend });
    } catch (e) {
      actions.push({ platform: 'meta', id: c.id, name: c.name, action: 'pause_failed', error: String(e.message), roas: c.roas });
    }

  } else if (c.roas > scaleAbove && c.status === 'ACTIVE' && c.daily_budget) {
    // ── SCALE UP budget +15% ─────────────────────────────────────────────────
    const newBudgetCents = Math.round(c.daily_budget * 1.15 * 100);
    try {
      await this.helpers.request({
        method: 'POST',
        uri: `https://graph.facebook.com/v19.0/${c.id}`,
        qs: { access_token: metaToken, daily_budget: newBudgetCents },
        json: true
      });
      actions.push({ platform: 'meta', id: c.id, name: c.name, action: 'budget_scaled', roas: c.roas, spend: c.spend, old_budget: c.daily_budget, new_budget: newBudgetCents / 100 });
    } catch (e) {
      actions.push({ platform: 'meta', id: c.id, name: c.name, action: 'scale_failed', error: String(e.message), roas: c.roas });
    }

  } else {
    // ── No action needed — within healthy range ───────────────────────────────
    recommendations.push({ platform: 'meta', id: c.id, name: c.name, roas: c.roas, spend: c.spend, reason: 'healthy' });
  }
}

const paused = actions.filter(a => a.action === 'paused').length;
const scaled = actions.filter(a => a.action === 'budget_scaled').length;
const failed = actions.filter(a => a.action.includes('failed')).length;

return [{ json: {
  ok: true,
  summary: { paused, scaled, failed, recommendations: recommendations.length },
  actions,
  recommendations,
  thresholds: { pause_below: pauseBelow, scale_above: scaleAbove, min_spend: minSpend },
  ran_at: new Date().toISOString()
} }];
